// content_filter (source: n8n/shared/content_filter.js)
const PROFANITY_KO = ['바보', '멍청', '씨발', '개새끼', '지랄'];
const PROFANITY_EN = ['fuck', 'shit', 'asshole', 'idiot', 'bitch'];
const SELF_HARM = ['자해', '자살', '죽고 싶', 'kill myself', 'self harm', 'suicide'];

const body = $input.first().json.body || {};
const answers = body.answers || {};
const weekStart = body.week_start || '';
const userLocale = answers.user_locale || 'ko';
const mode = body.mode || (body.refinement ? 'refine' : 'initial');
const ruleBasedSeed = Array.isArray(body.rule_based_seed) ? body.rule_based_seed : [];
const enhanceObjective = body.enhance_objective || 'diversify_titles';
const previousTurns = Array.isArray(body.previous_turns) ? body.previous_turns : [];
const followupAnswers = body.followup_answers && typeof body.followup_answers === 'object' ? body.followup_answers : {};
const refinement = body.refinement && typeof body.refinement === 'object' ? body.refinement : null;
const pastCtx = answers.past_week_context && typeof answers.past_week_context === 'object' ? answers.past_week_context : null;

function reject(reason) {
  return [{ json: { valid: false, reason, systemPrompt: '', userPrompt: '' } }];
}

if (!body.answers || typeof body.answers !== 'object') return reject('missing_answers');
if (!weekStart || typeof weekStart !== 'string') return reject('missing_week_start');

const freeText = (answers.fixed_schedules || '').toString();
const lower = freeText.toLowerCase();
for (const word of SELF_HARM) if (lower.includes(word)) return reject('self_harm');
for (const word of [...PROFANITY_KO, ...PROFANITY_EN]) if (lower.includes(word)) return reject('profanity');

let sp = 'You are a weekly schedule planner. Output ONLY a single JSON object (no markdown, no reasoning prose).\n\n';

if (mode === 'enhance') {
  sp += 'ENHANCE MODE: Improve the rule-based seed below according to the requested objective.\n';
  sp += 'Preserve item count and day_of_week distribution. Diversify titles, naturalize Korean, refine tags.\n';
  sp += 'Rule-based seed: ' + JSON.stringify(ruleBasedSeed) + '\n';
  sp += 'Enhance objective: ' + enhanceObjective + '\n';
  sp += 'Output keys: items (enhanced array, same count), diff_summary (Korean 1-2 sentences), source ("llm").\n';
} else if (mode === 'refine') {
  sp += 'REFINEMENT MODE: Refine the previous weekly schedule using follow-up answers.\n';
  // Support both new (previous_turns/followup_answers) and legacy (refinement.previous_items)
  if (previousTurns.length > 0) {
    sp += 'Previous turns (last ' + previousTurns.length + '): ' + JSON.stringify(previousTurns) + '\n';
    sp += 'Follow-up answers: ' + JSON.stringify(followupAnswers) + '\n';
  } else if (refinement) {
    sp += 'Previous items: ' + JSON.stringify(refinement.previous_items || []) + '\n';
    sp += 'Follow-up answers: ' + JSON.stringify(refinement.followup_answers || {}) + '\n';
  }
  sp += 'Output keys: items (refined array), followup_questions (empty array), source ("llm"), diff_summary (Korean 1-2 sentences).\n';
} else {
  sp += 'INITIAL MODE: Generate a weekly schedule PLUS 3-5 follow-up questions that, if answered, would let you refine further.\n';
  sp += 'Output keys: items (10-18 items), followup_questions (3-5 questions), source ("llm").\n';
  sp += 'Follow-up format: {id (snake_case), question (Korean string), options (3-5 {value,label} pairs, all strings)}.\n';
}

sp += '\nItem schema: {title (Korean string), day_of_week (0-6, 0=Monday), start_time ("HH:MM"), end_time ("HH:MM"), category (one of: work, study, hobby, health, etc), tags (1-2 short strings)}.\n';
sp += 'Respect user wake/sleep, chronotype, focus time. Weekend days may differ from weekdays.\n';
sp += '\n[USER PROFILE]\n';
sp += 'Locale: ' + userLocale + '\n';
sp += 'Status: ' + (answers.status || '-') + ', Wake: ' + (answers.wake_time || '-') + ', Sleep: ' + (answers.sleep_time || '-') + '\n';
sp += 'Chronotype: ' + (answers.chronotype || '-') + ', Work days: ' + (answers.work_days || '-') + ', Work hours: ' + (answers.work_hours || '-') + '\n';
sp += 'Commute: ' + (answers.commute_time || '-') + ', Meals: ' + (answers.meal_pattern || '-') + ', Focus: ' + (answers.focus_time || '-') + '\n';
sp += 'Exercise: ' + (answers.exercise || '-') + ', Ex time: ' + (answers.exercise_preferred_time || '-') + ', Hobby: ' + (answers.hobby || '-') + '\n';
sp += 'Goal: ' + (answers.goal_focus || '-') + ', Free time: ' + (answers.free_time || '-') + ', Fixed: ' + (answers.fixed_schedules || '-');

if (pastCtx) {
  const rate = Math.round((pastCtx.weekly_completion_rate || 0) * 100);
  const focus = Math.round((pastCtx.focus_ratio_avg || 0) * 100);
  sp += '\n\n[PAST EXECUTION CONTEXT — last ' + (pastCtx.weeks_observed || 4) + ' weeks]\n';
  sp += `- 평균 완료율 ${rate}%, 평균 집중도 ${focus}%\n`;
  if (pastCtx.lowest_completion_category) sp += `- 가장 미이행 카테고리: ${pastCtx.lowest_completion_category}\n`;
  if (pastCtx.most_missed_time_block) sp += `- 가장 미이행 시간대: ${pastCtx.most_missed_time_block}\n`;
  sp += '규칙: 위 미이행 패턴을 고려해 부담을 낮추되, 동일 카테고리는 빈도/시간대 조정으로 재시도하라. 완료율이 50% 미만이면 일정 개수를 줄이고 난이도를 낮춰라.';
}

return [{ json: { valid: true, mode, answers, week_start: weekStart, userLocale, refinement, systemPrompt: sp, userPrompt: 'Output the JSON object now.' } }];

const res = $input.first().json;
let content = '';
if (typeof res.text === 'string') content = res.text;
else if (res.output && typeof res.output === 'object') content = JSON.stringify(res.output);
else if (typeof res.response === 'string') content = res.response;
else content = JSON.stringify(res);
content = content.trim();
if (content.startsWith('```')) {
  content = content.replace(/^```(?:json)?\s*\n?/i, '').replace(/\n?```\s*$/, '').trim();
}

const ALLOWED_CATEGORIES = ['work', 'study', 'hobby', 'health', 'etc'];
const TIME_RE = /^([01]\d|2[0-3]):[0-5]\d$/;

function presetItems() {
  return [
    { title: '집중 업무 블록', day_of_week: 0, start_time: '09:00', end_time: '11:00', category: 'work', tags: [] },
    { title: '집중 업무 블록', day_of_week: 1, start_time: '09:00', end_time: '11:00', category: 'work', tags: [] },
    { title: '집중 업무 블록', day_of_week: 2, start_time: '09:00', end_time: '11:00', category: 'work', tags: [] },
    { title: '집중 업무 블록', day_of_week: 3, start_time: '09:00', end_time: '11:00', category: 'work', tags: [] },
    { title: '집중 업무 블록', day_of_week: 4, start_time: '09:00', end_time: '11:00', category: 'work', tags: [] },
    { title: '운동', day_of_week: 0, start_time: '18:30', end_time: '19:30', category: 'health', tags: [] },
    { title: '운동', day_of_week: 2, start_time: '18:30', end_time: '19:30', category: 'health', tags: [] },
    { title: '운동', day_of_week: 4, start_time: '18:30', end_time: '19:30', category: 'health', tags: [] },
    { title: '취미·자기계발', day_of_week: 5, start_time: '10:00', end_time: '12:00', category: 'hobby', tags: [] }
  ];
}

let parsed;
try { parsed = JSON.parse(content); } catch (e) { parsed = null; }

if (!parsed || !Array.isArray(parsed.items) || parsed.items.length === 0) {
  return [{ json: { items: presetItems(), source: 'preset', followup_questions: [] } }];
}

const items = [];
for (const raw of parsed.items) {
  if (!raw || typeof raw !== 'object') continue;
  const title = typeof raw.title === 'string' ? raw.title.trim() : '';
  if (!title) continue;
  let dow = Number(raw.day_of_week);
  if (!Number.isFinite(dow)) continue;
  dow = Math.max(0, Math.min(6, Math.trunc(dow)));
  const start = typeof raw.start_time === 'string' ? raw.start_time.trim() : '';
  const end = typeof raw.end_time === 'string' ? raw.end_time.trim() : '';
  if (!TIME_RE.test(start) || !TIME_RE.test(end)) continue;
  const category = ALLOWED_CATEGORIES.includes(raw.category) ? raw.category : 'etc';
  const tags = Array.isArray(raw.tags) ? raw.tags.map(String) : [];
  items.push({ title, day_of_week: dow, start_time: start, end_time: end, category, tags });
}

if (items.length === 0) {
  return [{ json: { items: presetItems(), source: 'preset', followup_questions: [] } }];
}

const followupQuestions = [];
if (Array.isArray(parsed.followup_questions)) {
  for (const q of parsed.followup_questions) {
    if (!q || typeof q !== 'object') continue;
    const id = typeof q.id === 'string' ? q.id.trim() : '';
    const question = typeof q.question === 'string' ? q.question.trim() : '';
    if (!id || !question) continue;
    if (!Array.isArray(q.options) || q.options.length === 0) continue;
    const options = [];
    for (const opt of q.options) {
      if (!opt || typeof opt !== 'object') continue;
      const val = typeof opt.value === 'string' ? opt.value.trim() : '';
      const label = typeof opt.label === 'string' ? opt.label.trim() : '';
      if (!val || !label) continue;
      options.push({ value: val, label });
    }
    if (options.length === 0) continue;
    followupQuestions.push({ id, question, options });
  }
}

return [{ json: { items, source: 'llm', followup_questions: followupQuestions } }];

